import React, { useState } from 'react';

function SignUp() {
  // State untuk menampung input dari form
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  const [loading, setLoading] = useState(false);

  // Fungsi untuk menangani perubahan input
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // Fungsi untuk mengirim data ke Flask (Backend)
  const handleSignUp = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await fetch('http://127.0.0.1:5000/api/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const result = await response.json();

      if (response.ok) {
        alert("Pendaftaran Berhasil! Silakan masuk menggunakan akun baru.");
        window.location.href = "/"; // Arahkan kembali ke halaman Login
      } else {
        alert(result.message || "Gagal mendaftar");
      }
    } catch (error) {
      alert("Gagal terhubung ke server. Pastikan Flask sudah jalan!");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Daftar Admin Baru</h2>
        <p style={styles.subtitle}>Sistem Monitoring Smart Trash Bin</p>

        <form onSubmit={handleSignUp}>
          <div style={styles.inputGroup}>
            <input 
              type="text" 
              name="name"
              placeholder="Nama Lengkap" 
              style={styles.input}
              value={formData.name}
              onChange={handleChange}
              required 
            />
          </div>

          <div style={styles.inputGroup}>
            <input 
              type="email" 
              name="email"
              placeholder="Email Admin" 
              style={styles.input}
              value={formData.email}
              onChange={handleChange}
              required 
            />
          </div>
          
          <div style={styles.inputGroup}>
            <input 
              type="password" 
              name="password"
              placeholder="Buat Password" 
              style={styles.input}
              value={formData.password}
              onChange={handleChange}
              required 
            />
          </div>
          
          <button type="submit" style={styles.button} disabled={loading}>
            {loading ? "Memproses..." : "Daftar Akun"}
          </button>
        </form>

        <p style={styles.footerText}>
          Sudah punya akun? <a href="/" style={styles.link}>Login di sini</a>
        </p>
      </div>
    </div>
  );
}

// 🎨 Styles agar tampilannya seragam dengan halaman Login
const styles = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', backgroundColor: '#f0f2f5' },
  card: { padding: '40px', borderRadius: '15px', backgroundColor: '#fff', boxShadow: '0 8px 24px rgba(0,0,0,0.1)', width: '100%', maxWidth: '400px', textAlign: 'center' },
  title: { color: '#1a1a1a', marginBottom: '10px' },
  subtitle: { color: '#666', marginBottom: '30px', fontSize: '14px' },
  inputGroup: { marginBottom: '15px' },
  input: { width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '16px', boxSizing: 'border-box' },
  button: { width: '100%', padding: '12px', borderRadius: '8px', border: 'none', backgroundColor: '#28a745', color: 'white', fontSize: '16px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' },
  footerText: { marginTop: '20px', fontSize: '14px', color: '#555' },
  link: { color: '#007bff', textDecoration: 'none', fontWeight: 'bold' }
};

export default SignUp;
